create table nfce_serie (serie integer, ultimo_numero integer, id bigint generated by default as identity, primary key (id), unique (serie));
create table tb_destinatario (c_mun integer, indiedest integer, uf varchar(2), cep varchar(8), id bigint generated by default as identity, numero varchar(10), cpf varchar(11), cnpj varchar(14), bairro varchar(60), logradouro varchar(60), x_nome varchar(60), primary key (id));
create table tb_emitente (crt integer, emitente boolean, id bigint generated by default as identity, bairro varchar(60), x_fant varchar(60), c_mun varchar(255), cep varchar(255), cnpj varchar(255), ie varchar(255), logradouro varchar(255), numero varchar(255), uf varchar(255), x_mun varchar(255), x_nome varchar(255), primary key (id));
create table tb_historico_produto (quantidade float(53), saldo_anterior float(53), saldo_atual float(53), criado_em timestamp(6) with time zone, id bigint generated by default as identity, product_id bigint, referencia varchar(255), tipo_movimento varchar(255) check (tipo_movimento in ('ENTRADA','SAIDA','AJUSTE','VENDA')), primary key (id));
create table tb_item_nfce (preco_venda float(53), q_com float(53), nfce_id bigint not null, product_id bigint not null, codigo_principal varchar(255), descricao varchar(255), primary key (nfce_id, product_id));
create table tb_nfce (codigo_mensagem integer, codigo_municipio_fato_gerador integer, codigo_uf integer, codigo_verificador integer, desconto float(53), finalidade_emissao integer, formato_impressao integer, identificador_destino integer, serie integer, tipo_ambiente integer, tipo_de_operacao integer, tipo_emissao integer, valor_total_nota float(53), valor_total_produtos float(53), data_hora_contingencia timestamp(6), data_hora_emissao timestamp(6), destinatario_id bigint, empresa_id bigint, id bigint generated by default as identity, numero_nf bigint, pagamento_id bigint, informacoes varchar(2000), ambiente varchar(255), chave varchar(255), codigo_numerico varchar(255), id_api varchar(255) unique, justificativa_contingencia varchar(255), mensagem varchar(255), mod varchar(255), motivo_status varchar(255), nat_op varchar(255), protocolo varchar(255), qr_code TEXT, status varchar(255), token_fiscal varchar(255), primary key (id));
create table tb_pagamento (v_pag float(53), id bigint not null, t_pag varchar(255), primary key (id));
create table tb_product (ativo boolean, fcp_aliquota float(53), icms_aliquota float(53), ind_tot float(53), modalidade_bc integer, origem integer, preco_custo float(53), preco_venda float(53), q_trib float(53), quantidade float(53), valor_total_est float(53), vl_un_trib float(53), id bigint generated by default as identity, tributo_fiscal_id bigint, cest varchar(255), cfop varchar(255), codigo_barras varchar(255), codigo_principal varchar(255), cst varchar(255), descricao varchar(255), imagem_url TEXT, ncm varchar(255), u_com varchar(255), uf varchar(255), primary key (id));
create table tb_role (id bigint generated by default as identity, authority varchar(255), primary key (id));
create table tb_user (id bigint generated by default as identity, email varchar(255), name varchar(255), password varchar(255), phone varchar(255), primary key (id));
create table tb_user_role (role_id bigint not null, user_id bigint not null, primary key (role_id, user_id));
create table tributo_fiscal (ativo boolean, fcp_aliquota float(53), icms_aliquota float(53), modalidade_bc integer, origem integer, id bigint generated by default as identity, cst varchar(255), descricao varchar(255), uf varchar(255), primary key (id));
alter table if exists tb_historico_produto add constraint FKg3minl8vq9mjhokc01ixp9cg foreign key (product_id) references tb_product;
alter table if exists tb_item_nfce add constraint FK21h2fja91ykmkw8ssurvb9qrl foreign key (product_id) references tb_product;
alter table if exists tb_item_nfce add constraint FKccetnvi1oshvy5ud816j5s1i7 foreign key (nfce_id) references tb_nfce;
alter table if exists tb_nfce add constraint FK74d8ordiucfuv22u4jcowlejl foreign key (destinatario_id) references tb_destinatario;
alter table if exists tb_nfce add constraint FKi3qs5p82mqto9cl77oxffe4fl foreign key (empresa_id) references tb_emitente;
alter table if exists tb_nfce add constraint FKk2n3ix3lgnq5if0s8c4cifq26 foreign key (pagamento_id) references tb_pagamento;
alter table if exists tb_user_role add constraint FKea2ootw6b6bb0xt3ptl28bymv foreign key (role_id) references tb_role;
